// bundle-advice.mjs — собирает advice/_*.js модули в heys_advice_bundle_v1.js.
//
// Список источников = single source of truth в scripts/legacy-bundle-config.mjs
// (LEGACY_GENERATORS.advice.sources). Раньше список дублировался здесь и в
// конфиге — drift приводил к bundle без Phase 1 evidence (incident 2026-05-30).
//
// Запуск:
//   node apps/web/scripts/bundle-advice.mjs       — пересобрать bundle
//   через predev/prebuild и pre-commit auto-sync
//
// Output: apps/web/heys_advice_bundle_v1.js (auto-generated, не редактируй вручную).

import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

import { LEGACY_GENERATORS } from '../../../scripts/legacy-bundle-config.mjs';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const WEB_ROOT = path.resolve(__dirname, '..');
const OUT_FILE = path.join(WEB_ROOT, 'heys_advice_bundle_v1.js');

const sources = LEGACY_GENERATORS.advice.sources;

const banner = [
    '// heys_advice_bundle_v1.js — bundled advice modules (core + categories)',
    '// ⚠️ Auto-generated by apps/web/scripts/bundle-advice.mjs. Do not edit manually.',
    '// Sources: scripts/legacy-bundle-config.mjs → LEGACY_GENERATORS.advice.sources',
    '',
].join('\n');

const chunks = [banner];

for (const sourcePath of sources) {
    const relativeToWeb = sourcePath.startsWith('apps/web/')
        ? sourcePath.slice('apps/web/'.length)
        : sourcePath;
    const absPath = path.join(WEB_ROOT, relativeToWeb);

    if (!fs.existsSync(absPath)) {
        throw new Error(`[bundle-advice] Missing source file: ${sourcePath}`);
    }

    const raw = fs.readFileSync(absPath, 'utf8').trimEnd();
    const safeContent = raw.startsWith(';') ? raw : `;${raw}`;

    chunks.push(`// ===== Begin ${relativeToWeb} =====`);
    chunks.push(safeContent);
    chunks.push(`// ===== End ${relativeToWeb} =====`);
    chunks.push('');
}

fs.writeFileSync(OUT_FILE, chunks.join('\n'), 'utf8');

console.info(`[bundle-advice] ✅ Generated ${OUT_FILE} (${sources.length} modules)`);
